", "options": ["« Ça marchera forcément »", "« Qu''est-ce qui ferait que ça ne marcherait pas ? C''est pour ça qu''on a la garantie. »", "« On te rembourse »", "« Tu n''as qu''à essayer »"], "correct_index": 1, "explication": "Explorer la peur puis rassurer avec la garantie."}, {"question": "L''objection de support (conjoint/associé) cache souvent...", "contexte": "", "options": ["Un vrai besoin de consulter", "Un manque de confiance ou une peur de décider seul", "Un problème juridique", "Un budget insuffisant"], "correct_index": 1, "explication": "Souvent c''est une excuse pour ne pas décider sur le moment."}, {"question": "Face à « Pas convaincu(e) »...", "contexte": "", "options": ["« Pourtant c''est bien »", "« Qu''est-ce qui te ferait passer à 10/10 ? »", "« Tant pis »", "« Je te renvoie la présentation »"], "correct_index": 1, "explication": "Identifier précisément ce qui manque pour convaincre."}, {"question": "Combien de scripts d''objection sont enseignés dans la formation ?", "contexte": "", "options": ["5", "8", "12", "21"], "correct_index": 2, "explication": "12 scripts de base + la version étendue en ressource."}, {"question": "Le scénario Lina illustre...", "contexte": "", "options": ["Le prix comme objection", "Le Futur Pacing + Histoire Miroir contre la peur de l''échec", "L''abandon d''un prospect", "La négociation"], "correct_index": 1, "explication": "Lina utilise l''émotion pour traiter une objection de confiance."}]}'::jsonb);

select public.import_quiz_from_json('{"titre": "Quiz Closing — M7 Techniques de Closing", "description": "Quiz de validation du module 7 de la formation Closing.", "max_errors": 3, "status": "published", "module_id": "7c484bf5-c86b-4738-9ccb-b066b2cf48a5", "formation_id": null, "questions": [{"question": "Combien de techniques de closing sont enseignées ?", "contexte": "", "options": ["3", "4", "6", "10"], "correct_index": 2, "explication": "Question directe, Summary, Alternative, Futur Pacing, Histoire Miroir, Takeaway."}, {"question": "La question directe consiste à...", "contexte": "", "options": ["Poser 10 questions d''affilée", "Demander simplement « Qu''est-ce que tu décides ? » puis silence", "Questionner le budget", "Demander une note sur 10"], "correct_index": 1, "explication": "Simple, direct, efficace. Pour les profils analytiques."}, {"question": "Le Summary Close consiste à...", "contexte": "", "options": ["Résumer le prix", "Résumer la situation + la douleur + la solution et demander validation", "Résumer les bonus", "Résumer les objections"], "correct_index": 1, "explication": "« Vu tout ça, est-ce que c''est la bonne décision ? »"}, {"question": "L''Alternative Close consiste à...", "contexte": "", "options": ["Donner le choix entre acheter ou pas", "Donner le choix entre deux options (pas entre oui et non)", "Proposer deux prix", "Alterner les techniques"], "correct_index": 1, "explication": "« Tu préfères le paiement en 3 ou en 6 fois ? »"}, {"question": "Le Futur Pacing consiste à...", "contexte": "", "options": ["Parler du passé du prospect", "Créer une image mentale du succès futur", "Pacer son discours", "Accélérer le closing"], "correct_index": 1, "explication": "« Imagine dans 90 jours. Comment tu te sens ? »"}, {"question": "L''Histoire Miroir consiste à...", "contexte": "", "options": ["Raconter sa propre vie", "Raconter l''histoire d''un client dans une situation similaire", "Copier les gestes du prospect", "Lire des témoignages"], "correc