on consiste à...", "contexte": "", "options": ["Diriger la conversation de force", "Guider progressivement le prospect vers la décision après le pacing", "Parler avant le prospect", "Imposer son point de vue"], "correct_index": 1, "explication": "Pacing puis leading = synchroniser puis guider."}, {"question": "La visio est prioritaire sur le téléphone parce que...", "contexte": "", "options": ["C''est plus rapide", "Le langage corporel et les expressions faciales renforcent la confiance", "C''est à la mode", "Le prospect préfère"], "correct_index": 1, "explication": "La visio ajoute le non-verbal qui renforce la connexion."}, {"question": "Le scénario Samir illustre...", "contexte": "", "options": ["Le Takeaway Close", "La sélection de technique selon le profil du prospect", "L''abandon d''un prospect", "Le prix"], "correct_index": 1, "explication": "Samir choisit le Futur Pacing parce que le profil de Fatima est émotif."}, {"question": "Le scénario Mehdi illustre...", "contexte": "", "options": ["Le Summary Close", "Le Takeaway Close quand rien ne fonctionne", "Le Futur Pacing", "La question directe"], "correct_index": 1, "explication": "Mehdi retire l''offre — le prospect se bat pour rester."}, {"question": "Si le prospect est convaincu à 9/10, la technique la plus adaptée est...", "contexte": "", "options": ["Le Takeaway Close", "La question directe (simple et efficace)", "Le Summary Close détaillé", "L''Alternative Close"], "correct_index": 1, "explication": "À 9/10, pas besoin de technique lourde."}, {"question": "La reformulation sert à...", "contexte": "", "options": ["Gagner du temps", "Montrer que tu écoutes et valider ta compréhension", "Changer le sujet", "Impressionner le prospect"], "correct_index": 1, "explication": "La reformulation est un outil de connexion et de validation."}, {"question": "Les histoires en closing servent à...", "contexte": "", "options": ["Divertir", "Illustrer, rassurer et créer l''identification", "Remplir les silences", "Montrer son expérience"], "correct_index": 1, "explication": "Le prospect se projette dans l''histoire d''un autre client."}, {"question": "Le pacing/leading fonctionne parce que...", "contexte": "", "options": ["Le prospect obéit", "Le prospect suit naturellement quelqu''un qui l''a d''abord compris", "C''est de la manipulation", "Le prospect est fatigué"], "correct_index": 1, "explication": "Se synchroniser d''abord crée la confiance, puis guider devient naturel."}, {"question": "En visio, le closer doit...", "contexte": "", "options": ["Regarder son écran", "Regarder la caméra pour maintenir le contact visuel", "Couper sa caméra", "Lire son script à voix haute"], "correct_index": 1, "explication": "Le contact visuel en visio = regarder la caméra."}, {"question": "L''Alternative Close est efficace avec les profils hésitants parce que...", "contexte": "", "options": ["Elle force la décision", "Elle remplace le oui/non par un choix entre deux options positives", "Elle baisse le prix", "Elle crée de l''urgence"], "correct_index": 1, "explication": "Le choix guidé élimine le « non » comme option."}, {"question": "Le Futur Pacing est efficace parce que...", "contexte": "", "options": ["Il crée de la pression", "Le prospect ressent émotionnellement le succès futur", "Il est rapide", "Il impressionne"], "correct_index": 1, "explication": "L''image mentale du succès active le désir."}, {"question": "Quand Mehdi dit « Je ne suis pas sûr que ce soit pour toi »...", "contexte": "", "options": ["Il abandonne le prospect", "Il inverse la dynamique — le prospect se bat pour rester", "Il est honnête", "Il manque de conviction"], "correct_index": 1, "explication": "Le Takeaway crée le sursaut : c''est le prospect qui convainc le closer."}, {"question": "Les questions en closing servent à...", "contexte": "", "options": ["Vendre", "Comprendre, diagnostiquer et explorer les objections", "Impressionner", "Gagner du temps"], "correct_index": 1, "explication": "Poser des questions = comprendre, pas vendre."}, {"question": "L''erreur la plus courante en closing est de...", "contexte": "", "options": ["Poser trop de questions", "Ne pas demander la décision", "Être trop silencieux", "Écouter trop"], "correct_index": 1, "explication": "Si tu ne demandes pas, tu n''obtiendras pas."}, {"question": "Le combo Futur Pacing + Question directe est utilisé quand...", "contexte": "", "options": ["Le prospect est analytique", "Le prospect est émotif et presque convaincu", "Le prospect refuse", "Le closer est pressé"], "correct_index": 1, "explication": "Émotion (Futur Pacing) + closure (Question directe) = combo efficace."}, {"question": "Rendre la transformation simple signifie...", "contexte": "", "options": ["Baisser le prix", "Montrer que le chemin est facile et accessible, comme Amazon/Netflix", "Simplifier l''offre", "Réduire la durée"], "correct_index": 1, "explication": "Plus la transformation perçue est simple, plus le prospect avance."}, {"question": "La garantie dans le closing sert à...", "contexte": "", "options": ["Donner une impression de qualité", "Annuler le risque perçu et augmenter la certitude", "Respecter la loi", "Concurrencer les autres"], "correct_index": 1, "explication": "La garantie est un accélérateur de décision."}, {"question": "Le pacing/leading est une technique de...", "contexte": "", "options": ["Manipulation", "Communication authentique qui crée la confiance avant de guider", "Vente agressive", "Marketing"], "correct_index": 1, "explication": "Se synchroniser = confiance. Guider = naturel."}]}'::jsonb);

select public.import_quiz_from_json('{"titre": "Quiz Closing — M8 KPIs, Éthique & Progression", "description": "Quiz de validation du module 8 de la formation Closing.", "max_errors": 3, "status": "published", "module_id": "860abbef-9a48-4d2d-bc4e-1f068eb25bb0", "formation_id": null, "questions": [{"question": "Quel est le taux de closing visé pour un débutant (mois 1-2) ?", "contexte": "", "options": ["5-10%", "10-15%", "25-35%", "50%"], "correct_index": 1, "explication": "Taux visé débutant : 10-15%."}, {"question": "Quel est le taux de closing visé en phase intermédiaire (mois 3-4) ?", "contexte": "", "options": ["10-15%", "15-25%", "25-35%", "35-50%"], "correct_index": 2, "explication": "Taux visé intermédiaire : 25-35%."}, {"question": "Quel est le taux de closing visé en phase avancée (mois 5+) ?", "contexte": "", "options": ["25-35%", "30-40%", "35-50%", "50-70%"], "correct_index": 2, "explication": "Taux visé avancé : 35-50%."}, {"question": "Le plateau normal arrive vers...", "contexte": "", "options": ["Semaine 1-2", "Semaine 3-4", "Semaine 5-6", "Mois 3"], "correct_index": 2, "explication": "Plateau semaine 5-6 : ton taux peut stagner, c''est normal."}, {"question": "Quand le taux stagne, c''est le signe que...", "contexte": "", "options": ["Tu régresses", "Tu développes ton style personnel", "Tu dois tout changer", "Tu dois arrêter"], "correct_index": 1, "explication": "Le plateau est le signe que tu développes ton style."}, {"question": "L''erreur fatale n°1 est...", "contexte": "", "options": ["Parler trop", "Pitcher avant d''avoir diagnostiqué", "Ne pas closer", "Remplir les silences"], "correct_index": 1, "explication": "Tu ne sais pas encore ce que le prospect veut."}, {"question": "L''erreur fatale n°2 est...", "contexte": "", "options": ["Pitcher trop tôt", "Parler plus de 30% du temps", "Ne pas enregistrer", "Céder sur le prix"], "correct_index": 1, "explication": "Un closer qui parle trop ferme mal. Règle 70/30."}, {"question": "L''erreur fatale n°3 est...", "contexte": "", "options": ["Parler trop", "Pitcher trop tôt", "Remplir les silences", "Prendre les refus personnellement"], "correct_index": 2, "explication": "Le silence est ton arme n°1, pas ton ennemi."}, {"question": "Combien d''erreurs fatales sont enseignées ?", "contexte": "", "options": ["5", "7", "10", "15"], "correct_index": 2, "explication": "Les 10 erreurs fatales du closer."}, {"question": "Enregistrer ses appels est important parce que...", "contexte": "", "options": ["C''est obligatoire légalement", "Impossible de progresser sans feedback objectif", "Le prospect le demande", "C''est à la mode"], "correct_index": 1, "explication": "Sans réécoute, pas de progression mesurable."}, {"question": "Le plan de progression sur 90 jours se divise en...", "contexte": "", "options": ["2 phases", "3 phases", "4 phases", "5 phases"], "correct_index": 1, "explication": "Mois 1-2 (bases), mois 3-4 (consolidation), mois 5-6 (maîtrise)."}, {"question": "En mois 1-2, l''objectif principal est de...", "contexte": "", "options": ["Closer à 50%", "Apprendre les scripts + 5 role plays/jour + enregistrer chaque appel", "Former d''autres closers", "Créer son propre script"], "correct_index": 1, "explication": "Phase d''apprentissage : scripts, pratique, enregistrement."}, {"question": "En mois 3-4, l''objectif est de...", "contexte": "", "options": ["Continuer les scripts de base", "Maîtriser 12 objections sans script + analyser 3 zones/semaine", "Former une équipe", "Changer d''offre"], "correct_index": 1, "explication": "Phase de consolidation : sans filet + auto-analyse."}, {"question": "En mois 5+, le closer doit...", "contexte": "", "options": ["Revenir aux bases", "Adapter le script à son style + pré-anticiper les objections + former d''autres closers", "Arrêter de s''enregistrer", "Tout automatiser"], "correct_index": 1, "explication": "Phase de maîtrise : style personnel + mentorat."}, {"question": "La grille d''analyse d''un appel doit être remplie...", "contexte": "", "options": ["Une fois par semaine", "Après chaque appel pendant 30 jours", "Une fois par mois", "Jamais, c''est optionnel"], "correct_index": 1, "explication": "La progression est mesurable dès la semaine 2."}, {"question": "Le ratio de parole à surveiller est...", "contexte": "", "options": ["50/50", "70/30 (prospect/closer)", "80/20", "60/40"], "correct_index": 1, "explication": "Si le closer parle plus de 30%, il parle trop."}, {"question": "Que réécouter en priorité ?", "contexte": "", "options": ["Ses meilleurs appels", "Ses 3 pires appels de la semaine", "Les appels des collègues", "Les podcasts de vente"], "correct_index": 1, "explication": "Les erreurs sont visibles dans les pires appels, pas les meilleurs."}, {"question": "Le coaching entre closers consiste à...", "contexte": "", "options": ["Se critiquer mutuellement", "Chacun réécoute un appel de l''autre par semaine et donne du feedback", "Comparer les KPIs", "Se disputer les leads"], "correct_index": 1, "explication": "Le feedback entre pairs accélère la progression."}, {"question": "L''organisation quotidienne recommandée est...", "contexte": "", "options": ["Appels toute la journée sans pause", "Blocs d''appels + analyse + relances + reporting KPIs", "Freestyle sans planning", "Uniquement des appels le matin"], "correct_index": 1, "explication": "08h-09h revue, 09h-12h bloc 1, 13h-14h analyse, 14h-17h bloc 2, 17h30 reporting."}, {"question": "Les outils recommandés sont...", "contexte": "", "options": ["Un carnet et un stylo", "CRM (HubSpot/GHL), Calendly, Zoom/Meet, Gong.io/Otter.ai", "Uniquement WhatsApp", "Excel"], "correct_index": 1, "explication": "CRM + calendrier + visio + outil d''analyse d''appel."}, {"question": "Le scénario Inaya montre...", "contexte": "", "options": ["Un échec total", "Un parcours de 6 mois avec un moment de doute au mois 3 et un rebond", "Une vente rapide", "Un abandon"], "correct_index": 1, "explication": "12% → doute mois 3 → mentor → 34% → 41%."}, {"question": "Le moment de doute d''Inaya arrive à...", "contexte": "", "options": ["Mois 1", "Mois 3 (3 refus consécutifs)", "Mois 5", "Jamais"], "correct_index": 1, "explication": "3 refus consécutifs. Doute. Hésite à continuer."}, {"question": "Ce qui fait rebondir Inaya est...", "contexte": "", "options": ["Une prime", "Son mentor qui la recadre", "Un gros close", "Un changement d''offre"], "correct_index": 1, "explication": "Le mentor la recadre. Elle se force au silence. Taux remonte."}, {"question": "Le scénario Nadia illustre...", "contexte": "", "options": ["Le close parfait", "La disqualification éthique quand le fit n''est pas là", "L''abandon d''un prospect", "Un refus du closer"], "correct_index": 1, "explication": "Le closer éthique sait dire non quand le budget est insuffisant."}, {"question": "Disqualifier un prospect est...", "contexte": "", "options": ["Un échec", "Un acte éthique et professionnel", "Interdit", "Une perte de temps"], "correct_index": 1, "explication": "Pas de vente. Nadia revient 3 mois plus tard avec le budget."}, {"question": "Vendre à des prospects non qualifiés est une erreur parce que...", "contexte": "", "options": ["C''est illégal", "Tu perds du temps et de l''énergie précieuse", "Le prospect se plaindra", "C''est une mauvaise pub"], "correct_index": 1, "explication": "Erreur fatale n°9 : prospects non qualifiés = temps perdu."}, {"question": "Manquer de conviction dans l''offre signifie...", "contexte": "", "options": ["Être modeste", "Si tu n''y crois pas, personne n''y croira", "Être réaliste", "Être prudent"], "correct_index": 1, "explication": "Erreur fatale n°10 : la conviction est contagieuse — dans les deux sens."}, {"question": "Céder sur le prix sans raison est une erreur parce que...", "contexte": "", "options": ["Le prospect sera insatisfait", "Tu brises la valeur perçue de l''offre", "C''est illégal", "Tu perds de l''argent"], "correct_index": 1, "explication": "Baisser le prix = communiquer que l''offre ne vaut pas ce prix."}, {"question": "Le meilleur closer n''est pas celui qui parle le mieux, c''est...", "contexte": "", "options": ["Celui qui a le plus d''expérience", "Celui qui écoute le mieux", "Celui qui connaît le plus de techniques", "Celui qui parle le plus vite"], "correct_index": 1, "explication": "L''écoute est la compétence n°1 du closer."}, {"question": "Le template de débrief après un appel doit inclure...", "contexte": "", "options": ["Uniquement le résultat (close ou non)", "Ratio parole, diagnostic complet ?, silence respecté ?, objection principale, technique utilisée, note globale, 3 axes d''amélioration", "Juste une note sur 10", "Rien, c''est optionnel"], "correct_index": 1, "explication": "Un débrief complet identifie les axes d''amélioration concrets."}]}'::jsonb);

select public.import_quiz_from_json('{"titre": "Quiz Closing — Validation Finale", "description": "Quiz de validation finale de la formation Closing — requis pour valider l''étape du parcours AL BARAKA.", "max_errors": 5, "status": "published", "module_id": null, "formation_id": "7e533baa-7b5e-42cf-8473-6a9fd19c318f", "questions": [{"question": "Que signifie le D dans le framework DRASTE ?", "contexte": "", "options": ["Diagnostiquer", "Dédiaboliser", "Décider", "Dominer"], "correct_index": 1, "explication": "Dédiaboliser la vente : ce n''est pas de la manipulation, c''est un service."}, {"question": "Quelles sont les deux émotions tueuses de vente ?", "contexte": "", "options": ["Colère et tristesse", "Peur et excitation", "Stress et fatigue", "Impatience et déception"], "correct_index": 1, "explication": "La peur paralyse et l''excitation fait pitcher trop vite."}, {"question": "L''auto-sabotage du closer, c''est quand...", "contexte": "", "options": ["Le prospect ment", "Le closer fait une erreur qui tue la vente", "Le setter n''a pas qualifié", "L''offre est trop chère"], "correct_index": 1, "explication": "Parler trop, mal écouter, pitcher trop tôt, paniquer sur le prix."}, {"question": "Parmi ces qualités, laquelle n''est PAS une qualité du closer d''excellence ?", "contexte": "", "options": ["Écoute active", "Empathie", "Agressivité commerciale", "Résilience"], "correct_index": 2, "explication": "L''agressivité n''a pas sa place dans le closing éthique."}, {"question": "Que doit faire le closer AVANT chaque appel concernant ses émotions ?", "contexte": "", "options": ["Les amplifier pour être motivé", "Les libérer et repartir à zéro", "Les utiliser comme carburant", "Les ignorer complètement"], "correct_index": 1, "explication": "Chaque appel est un nouveau départ. Les émotions de la journée ne doivent pas interférer."}, {"question": "Les décisions d''achat sont prises...", "contexte": "", "options": ["Majoritairement de façon rationnelle", "Majoritairement de façon émotionnelle", "50% rationnel, 50% émotionnel", "Uniquement par la logique"], "correct_index": 1, "explication": "Le système émotionnel est le moteur principal de la décision."}, {"question": "Quand le closer pose des questions sur la douleur avec une intention bonne, c''est...", "contexte": "", "options": ["De la manipulation", "Éthique et nécessaire", "Interdit par la loi", "Risqué"], "correct_index": 1, "explication": "Tout part de l''intention. Si l''intention est d''aider, vas-y."}, {"question": "La confiance par la conviction repose sur...", "contexte": "", "options": ["Des arguments logiques", "L''énergie, la voix et la certitude du closer", "Des réductions", "Des promesses exagérées"], "correct_index": 1, "explication": "Ton enthousiasme et ta certitude se font ressentir."}, {"question": "La réciprocité en vente signifie...", "contexte": "", "options": ["Échanger des cadeaux", "Donner de la valeur dans l''appel crée un sentiment de redevabilité", "Rendre la pareille au prospect", "Offrir une réduction"], "correct_index": 1, "explication": "Quand tu donnes de la valeur, la personne se sent positivement redevable."}, {"question": "Les boutons de confiance sont...", "contexte": "", "options": ["Des techniques de manipulation", "Des leviers concrets sur lesquels appuyer selon le moment de l''appel", "Des réductions à offrir", "Des arguments de vente"], "correct_index": 1, "explication": "Témoignages, storytelling, inversion du risque, preuve sociale, autorité."}, {"question": "The GAP représente...", "contexte": "", "options": ["L''écart de prix", "Le pont entre la situation actuelle et la situation souhaitée", "Un outil CRM", "Le temps de l''appel"], "correct_index": 1, "explication": "Situation actuelle → ton offre (le pont) → situation souhaitée."}, {"question": "Pourquoi relire le formulaire du prospect avant l''appel ?", "contexte": "", "options": ["Pour gagner du temps", "Pour identifier les signaux forts et zones de risque", "Par obligation légale", "Pour remplir le CRM"], "correct_index": 1, "explication": "Les signaux forts et zones de risque sont dans le formulaire."}, {"question": "Les citations à relire avant chaque appel servent à...", "contexte": "", "options": ["Impressionner le prospect", "Recadrer le mindset du closer avant l''appel", "Remplir le temps", "Décorer le bureau"], "correct_index": 1, "explication": "Recalibrer l''intention et le mindset."}, {"question": "Un signal fort dans un formulaire, c''est...", "contexte": "", "options": ["Une faute d''orthographe", "Un indice que le prospect est prêt ou motivé", "Un numéro de téléphone", "La date de remplissage"], "correct_index": 1, "explication": "Les signaux forts indiquent la motivation ou la douleur du prospect."}, {"question": "Le mindset « nouveau départ » avant chaque appel signifie...", "contexte": "", "options": ["Oublier toutes les techniques", "L''appel précédent (réussi ou raté) ne doit pas influencer le suivant", "Changer de script à chaque appel", "Ne pas se souvenir du prospect"], "correct_index": 1, "explication": "Chaque prospect mérite un closer frais et concentré."}, {"question": "Que signifie DECODE ?", "contexte": "", "options": ["Un logiciel de vente", "Les 6 phases de la structure d''appel", "Un type d''objection", "Un KPI"], "correct_index": 1, "explication": "DECODE = 6 phases structurées de l''appel de closing."}, {"question": "Après le diagnostic, que fait le closer avant de passer à l''offre ?", "contexte": "", "options": ["Il pitcher immédiatement", "Il fait une confirmation miroir de tout ce qui a été dit", "Il annonce le prix", "Il pose d''autres questions"], "correct_index": 1, "explication": "Ne JAMAIS passer à l''offre sans confirmation des 5 niveaux."}, {"question": "La prise de conscience consiste à...", "contexte": "", "options": ["Aider le prospect à mesurer l''ampleur de sa situation", "Donner des conseils gratuits", "Pitcher l''offre", "Critiquer le prospect"], "correct_index": 0, "explication": "Poser des questions profondes pour que le prospect réalise sa situation."}, {"question": "La phase Offre consiste à...", "contexte": "", "options": ["Lister toutes les fonctionnalités", "Présenter l''offre comme un pont entre la situation actuelle et le résultat", "Annoncer le prix", "Négocier"], "correct_index": 1, "explication": "Pont entre situation actuelle → ta solution → situation désirée."}, {"question": "Combien de relances maximum après un refus clair ?", "contexte": "", "options": ["1", "2", "5", "Autant que nécessaire"], "correct_index": 1, "explication": "2 relances maximum après un refus clair."}, {"question": "La confirmation miroir sert à...", "contexte": "", "options": ["Impressionner le prospect", "Résumer tout le diagnostic pour obtenir un « oui » avant l''offre", "Copier ses gestes", "Annoncer le prix"], "correct_index": 1, "explication": "Le prospect valide que tu as bien compris avant de passer à l''offre."}, {"question": "Le mirroring vocal consiste à...", "contexte": "", "options": ["Imiter la voix du prospect", "Adapter son rythme et son énergie au profil du prospect", "Parler plus fort que le prospect", "Utiliser un accent"], "correct_index": 1, "explication": "Analytique = calme et posé. Émotif = dynamique et engagé."}, {"question": "Le silence du prospect après le prix signifie souvent...", "contexte": "", "options": ["Qu''il a raccroché", "Qu''il réfléchit — c''est bon signe", "Qu''il n''est pas intéressé", "Qu''il attend une réduction"], "correct_index": 1, "explication": "Le silence est le signe que le prospect traite l''information."}, {"question": "Baisser le volume de la voix crée...", "contexte": "", "options": ["De la confusion", "De l''intimité et de la confiance", "De la distance", "De l''ennui"], "correct_index": 1, "explication": "Le prospect se rapproche quand la voix baisse."}, {"question": "Quand le prospect dit « C''est beaucoup... mais concrètement comment ça se passe ? » après un silence...", "contexte": "", "options": ["Le silence a échoué", "Le silence a fonctionné — le prospect passe de la résistance à la curiosité", "Il faut baisser le prix", "Il faut raccrocher"], "correct_index": 1, "explication": "Le silence transforme la résistance en question — c''est positif."}, {"question": "Une objection est...", "contexte": "", "options": ["Un refus définitif", "Une manière pour le prospect de se protéger", "Une tentative de négociation", "Un signe de désintérêt"], "correct_index": 1, "explication": "Une objection est un mécanisme de protection instinctif."}, {"question": "Quelle est l''objection la plus compliquée à traiter ?", "contexte": "", "options": ["Le prix", "L''incertitude (le prospect ne croit pas au produit)", "Le support (en parler au conjoint)", "Le timing"], "correct_index": 1, "explication": "L''incertitude est la plus complexe car elle touche à la confiance."}, {"question": "Si le prospect est à 6/10 sur l''échelle, la question est...", "contexte": "", "options": ["« Pourquoi pas 10 ? »", "« Qu''est-ce qui t''empêche d''être à 9 ou 10 ? »", "« Tu veux qu''on baisse le prix ? »", "« On rappelle demain ? »"], "correct_index": 1, "explication": "Identifier ce qui manque pour monter à 9-10."}, {"question": "Face à « J''ai déjà essayé et ça n''a pas marché »...", "contexte": "", "options": ["« Cette fois ce sera différent »", "« Qu''est-ce qui n''a pas fonctionné précisément ? »", "« On est meilleurs que les autres »", "« Oublie le passé »"], "correct_index": 1, "explication": "Identifier ce qui n''a pas marché pour se différencier."}, {"question": "La garantie est un levier de...", "contexte": "", "options": ["Prix", "Certitude — elle annule le risque perçu", "Support", "Timing"], "correct_index": 1, "explication": "La garantie augmente la certitude en réduisant le risque."}, {"question": "Combien de techniques de closing sont enseignées ?", "contexte": "", "options": ["3", "4", "6", "10"], "correct_index": 2, "explication": "Question directe, Summary, Alternative, Futur Pacing, His